const testCases = [
  {
    test_id: 'TC001',
    category: 'health_check',
    question: 'What is my current portfolio health score? List all risk flags and give me the diversification score.',
    expected_tools: ['getPortfolioHealthScore'],
    rubric: {
      mentions_score: '\\d+/100|score.*\\d+|\\d+.*score|health.*\\d+',
      mentions_flags: 'flag|risk|concentration|concern|warning',
      gives_recommendation: 'recommend|suggest|consider|should|action',
      uses_rupee_or_pct: '₹|%|percent|lakh|crore',
      mentions_component: 'diversification|liquidity|cost|returns|component'
    }
  },
  {
    test_id: 'TC002',
    category: 'stress_test',
    question: 'How would my portfolio have performed in the 2008 global financial crisis? What was the estimated drawdown percentage and how many months to recover?',
    expected_tools: ['getPortfolioStressTest'],
    rubric: {
      mentions_gfc: '2008|financial crisis|GFC|global financial',
      mentions_drawdown: 'drawdown|fall|drop|decline|fell|lost',
      mentions_percentage: '\\d+%|percent|\\d+\\.\\d+%',
      mentions_recovery: 'recover|months|years|bounce back',
      uses_specific_numbers: '\\d+\\.\\d+|\\d+,\\d+'
    }
  },
  {
    test_id: 'TC003',
    category: 'tax_redemption',
    question: 'I need Rs 2 lakhs urgently for a medical emergency. Which specific funds should I redeem and in what order to minimize capital gains tax?',
    expected_tools: ['getSmartRedemptionPlan', 'getTaxAwareRedemptionPlan'],
    rubric: {
      mentions_ltcg: 'LTCG|long.term capital|long term gain',
      mentions_stcg: 'STCG|short.term capital|short term gain',
      mentions_specific_fund: 'fund|scheme|plan|direct|growth',
      mentions_net_amount: 'net amount|after tax|net proceeds|in hand',
      mentions_order: 'first|then|next|order|sequence|priority'
    }
  },
  {
    test_id: 'TC004',
    category: 'sip_projection',
    question: 'If I start a SIP of Rs 20,000 per month in HDFC Flexi Cap Fund for 15 years assuming 13% annual returns, how much total corpus will I accumulate?',
    expected_tools: ['getSipProjection'],
    rubric: {
      mentions_corpus: 'corpus|total|accumulated|maturity|value',
      mentions_invested: 'invested|invest|total investment',
      mentions_large_number: 'crore|lakh|\\d{2},\\d{2},\\d{3}|\\d+\\.\\d+ cr',
      mentions_time: '15 year|fifteen year|period',
      mentions_gain: 'gain|profit|growth|wealth'
    }
  },
  {
    test_id: 'TC005',
    category: 'fund_comparison',
    question: 'Compare HDFC Mid Cap Opportunities Fund and Nippon India Growth Fund in terms of alpha generation vs their benchmark. Which one should I prefer?',
    expected_tools: ['comparePortfolioFunds', 'getFundVsIndexComparison'],
    rubric: {
      mentions_both_funds: '(?=.*HDFC)(?=.*Nippon)|(?=.*Nippon)(?=.*HDFC)',
      mentions_alpha: 'alpha|benchmark|outperform|beat',
      gives_clear_recommendation: 'recommend|prefer|better|choose|switch|stay|retain',
      mentions_returns: 'return|XIRR|%|performance',
      provides_comparison: 'vs|compared|versus|better than|higher than|lower than'
    }
  }
];

return testCases.map(tc => ({ json: tc }));

const testCase = $node['Process One Test at a Time'].json;
const agentResponse = $input.first().json;
const aiAnswer = agentResponse.output || '';
const steps = agentResponse.intermediateSteps || [];
const toolsUsed = [...new Set(steps.map(s => s.action?.tool).filter(Boolean))];

const rubric = testCase.rubric;
const expectedTools = testCase.expected_tools;

const rubricResults = {};
let rubricScore = 0;
const maxRubricScore = Object.keys(rubric).length;

Object.entries(rubric).forEach(([criterion, pattern]) => {
  let passed = false;
  try {
    const regex = new RegExp(pattern, 'is');
    passed = regex.test(aiAnswer);
  } catch(e) {
    passed = aiAnswer.toLowerCase().includes(pattern.toLowerCase());
  }
  rubricResults[criterion] = passed;
  if (passed) rubricScore++;
});

const toolsCorrect = expectedTools.some(t => toolsUsed.includes(t));
const unexpectedTools = toolsUsed.filter(t => !expectedTools.includes(t));
const toolScore = toolsCorrect ? 1 : 0;

const rawScore = (rubricScore / maxRubricScore) * 4 + toolScore;
const totalScore = Math.round(rawScore);
const passed = totalScore >= 3;

const approxTokens = Math.round((aiAnswer.length + testCase.question.length) / 4);

return [{
  json: {
    test_id: testCase.test_id,
    category: testCase.category,
    question: testCase.question,
    ai_answer_preview: aiAnswer.slice(0, 800),
    tools_used: toolsUsed,
    expected_tools: expectedTools,
    tools_correct: toolsCorrect,
    unexpected_tools: unexpectedTools,
    rubric_results: rubricResults,
    rubric_score: rubricScore,
    max_rubric_score: maxRubricScore,
    tool_score: toolScore,
    total_score: totalScore,
    max_score: 5,
    passed,
    score_pct: Math.round((totalScore / 5) * 100),
    approx_tokens: approxTokens,
    evaluated_at: new Date().toISOString()
  }
}];

const results = $input.all().map(i => i.json);

const totalTests = results.length;
const passedCount = results.filter(r => r.passed).length;
const failedCount = totalTests - passedCount;
const avgScore = results.reduce((s, r) => s + r.total_score, 0) / totalTests;
const avgRubricPct = results.reduce((s, r) => s + r.score_pct, 0) / totalTests;
const totalTokens = results.reduce((s, r) => s + r.approx_tokens, 0);
const toolAccuracy = results.filter(r => r.tools_correct).length / totalTests;

const byCategory = {};
results.forEach(r => {
  if (!byCategory[r.category]) byCategory[r.category] = { tests: 0, passed: 0, total_score: 0 };
  byCategory[r.category].tests++;
  if (r.passed) byCategory[r.category].passed++;
  byCategory[r.category].total_score += r.total_score;
});

const categoryBreakdown = Object.entries(byCategory).map(([cat, data]) => ({
  category: cat,
  tests: data.tests,
  pass_rate_pct: Math.round((data.passed / data.tests) * 100),
  avg_score: Math.round((data.total_score / data.tests) * 10) / 10
}));

const grade = avgScore >= 4.5 ? 'A+' : avgScore >= 4 ? 'A' : avgScore >= 3.5 ? 'B+' : avgScore >= 3 ? 'B' : avgScore >= 2 ? 'C' : 'D';

const failedTests = results.filter(r => !r.passed).map(r => ({
  test_id: r.test_id,
  category: r.category,
  score: r.total_score,
  missing_rubric: Object.entries(r.rubric_results).filter(([k, v]) => !v).map(([k]) => k)
}));

return [{
  json: {
    run_id: 'EVAL-' + Date.now(),
    run_date: new Date().toISOString().slice(0, 10),
    run_timestamp: new Date().toISOString(),
    summary: {
      total_tests: totalTests,
      passed: passedCount,
      failed: failedCount,
      pass_rate_pct: Math.round((passedCount / totalTests) * 100),
      avg_score_out_of_5: Math.round(avgScore * 10) / 10,
      avg_rubric_score_pct: Math.round(avgRubricPct),
      tool_selection_accuracy_pct: Math.round(toolAccuracy * 100),
      total_tokens_consumed: totalTokens,
      overall_grade: grade
    },
    category_breakdown: categoryBreakdown,
    failed_tests: failedTests,
    individual_results: results
  }
}];

